     1→import React, { useState, useEffect } from "react";
     2→import { Outlet, useNavigate, useLocation, useSearchParams } from "react-router-dom";
     3→import {
     4→  AppShell, Box, Text, NavLink, ActionIcon, Tooltip, Group, Anchor, TextInput, Select,
     5→  useMantineColorScheme, useComputedColorScheme,
     6→} from "@mantine/core";
     7→import { useDisclosure } from "@mantine/hooks";
     8→import { useBreadcrumb } from "./BreadcrumbContext";
     9→import { fetchBranches } from "./api";
    10→
    11→const NAV_ITEMS = [
    12→  { label: "Sessions",     path: "/",                     sym: "≡"  },
    13→  { label: "Session Tree", path: "/session-tree",         sym: "⬡"  },
    14→  { label: "Checkpoints",  path: "/checkpoints",          sym: "⬛" },
    15→  { label: "Timeline",     path: "/checkpoints/timeline", sym: "◎"  },
    16→  { label: "Repos",        path: "/repos",                sym: "⊡"  },
    17→] as const;
    18→
    19→const TOP_LEVEL = new Set(["/", "/session-tree", "/checkpoints", "/checkpoints/timeline", "/repos"]);
    20→
    21→function getActiveNav(pathname: string): string {
    22→  if (pathname === "/" || pathname.startsWith("/sessions/")) return "/";
    23→  if (pathname === "/session-tree") return "/session-tree";
    24→  if (pathname === "/checkpoints/timeline") return "/checkpoints/timeline";
    25→  if (pathname.startsWith("/checkpoints")) return "/checkpoints";
    26→  if (pathname === "/repos") return "/repos";
    27→  return "";
    28→}
    29→
    30→function BranchSelector({ localPath, branch, repoName }: { localPath: string; branch: string; repoName: string | null }) {
    31→  const navigate = useNavigate();
    32→  const [branches, setBranches] = useState<string[]>([]);
    33→  const [loading, setLoading] = useState(true);
    34→
    35→  useEffect(() => {
    36→    setLoading(true);
    37→    fetchBranches(localPath)
    38→      .then(setBranches)
    39→      .catch(() => setBranches(branch ? [branch] : []))
    40→      .finally(() => setLoading(false));
    41→  }, [localPath]);
    42→
    43→  return (
    44→    <Select
    45→      size="xs"
    46→      value={branch}
    47→      data={branches}
    48→      disabled={loading}
    49→      placeholder={loading ? "loading…" : undefined}
    50→      onChange={(b) => {
    51→        if (!b) return;
    52→        navigate(`/branch-log?localPath=${encodeURIComponent(localPath)}&branch=${encodeURIComponent(b)}${repoName ? `&repoName=${encodeURIComponent(repoName)}` : ""}`);
    53→      }}
    54→      styles={{ input: { fontFamily: "monospace", fontSize: 12 } }}
    55→      comboboxProps={{ withinPortal: true }}
    56→      allowDeselect={false}
    57→      w={200}
    58→    />
    59→  );
    60→}
    61→
    62→export function Layout() {
    63→  const navigate = useNavigate();
    64→  const { pathname } = useLocation();
    65→  const [searchParams] = useSearchParams();
    66→  const { toggleColorScheme } = useMantineColorScheme();
    67→  const colorScheme = useComputedColorScheme("dark");
    68→  const [sidebarOpen, { toggle: toggleSidebar }] = useDisclosure(true);
    69→  const { crumbs } = useBreadcrumb();
    70→  const [searchValue, setSearchValue] = useState("");
    71→
    72→  const isBranchLog = pathname === "/branch-log";
    73→  const branchLogLocalPath = isBranchLog ? (searchParams.get("localPath") ?? "") : "";
    74→  const branchLogBranch    = isBranchLog ? (searchParams.get("branch")    ?? "") : "";
    75→  const branchLogRepoName  = isBranchLog ? searchParams.get("repoName") : null;
    76→
    77→  const activeNav = getActiveNav(pathname);
    78→  const canGoBack = !TOP_LEVEL.has(pathname);
    79→
    80→  return (
    81→    <AppShell
    82→      header={{ height: 40 }}
    83→      navbar={{ width: 220, breakpoint: "sm", collapsed: { desktop: !sidebarOpen, mobile: !sidebarOpen } }}
    84→      padding={0}
    85→      style={{ height: "100vh" }}
    86→    >
    87→      {/* Header spans full width — hamburger is always visible */}
    88→      <AppShell.Header
    89→        style={{
    90→          borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
    91→          backgroundColor: "light-dark(var(--mantine-color-white), var(--mantine-color-dark-7))",
    92→        }}
    93→      >
    94→        <Group h="100%" px={12} gap={6} style={{ flex: 1 }}>
    95→          <ActionIcon variant="subtle" color="gray" onClick={toggleSidebar} size="sm" title="Toggle sidebar">
    96→            ☰
    97→          </ActionIcon>
    98→          {canGoBack && (
    99→            <ActionIcon variant="subtle" color="gray" onClick={() => navigate(-1)} size="sm" title="Back">
   100→              ←
   101→            </ActionIcon>
   102→          )}
   103→          {crumbs.length > 0 && (
   104→            <Group gap={4} align="center" ml={4}>
   105→              {crumbs.map((crumb, i) => (
   106→                <React.Fragment key={i}>
   107→                  {i > 0 && (
   108→                    <Text size="sm" c="dimmed" style={{ userSelect: "none" }}>/</Text>
   109→                  )}
   110→                  {crumb.path ? (
   111→                    <Anchor
   112→                      size="sm"
   113→                      fw={500}
   114→                      onClick={() => navigate(crumb.path!)}
   115→                      style={{ cursor: "pointer" }}
   116→                      underline="never"
   117→                    >
   118→                      {crumb.label}
   119→                    </Anchor>
   120→                  ) : (
   121→                    <Text size="sm" fw={500} c="dimmed">{crumb.label}</Text>
   122→                  )}
   123→                </React.Fragment>
   124→              ))}
   125→            </Group>
   126→          )}
   127→          {isBranchLog && branchLogLocalPath && branchLogBranch && (
   128→            <BranchSelector
   129→              localPath={branchLogLocalPath}
   130→              branch={branchLogBranch}
   131→              repoName={branchLogRepoName}
   132→            />
   133→          )}
   134→          <Box style={{ flex: 1 }} />
   135→          <TextInput
   136→            placeholder="Search logs…"
   137→            size="xs"
   138→            radius="md"
   139→            value={searchValue}
   140→            onChange={(e) => setSearchValue(e.currentTarget.value)}
   141→            onKeyDown={(e) => {
   142→              if (e.key === "Enter" && searchValue.trim()) {
   143→                navigate(`/search?q=${encodeURIComponent(searchValue.trim())}`);
   144→              }
   145→            }}
   146→            style={{ width: 220 }}
   147→          />
   148→        </Group>
   149→      </AppShell.Header>
   150→
   151→      <AppShell.Navbar
   152→        style={{
   153→          backgroundColor: "light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-8))",
   154→          borderRight: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
   155→          display: "flex",
   156→          flexDirection: "column",
   157→          padding: "12px 8px",
   158→        }}
   159→      >
   160→        <Text fw={700} size="sm" px={8} py={6} mb={8} style={{ letterSpacing: 0.2 }}>
   161→          Gossamer
   162→        </Text>
   163→
   164→        <Box style={{ flex: 1 }}>
   165→          {NAV_ITEMS.map(({ label, path, sym }) => (
   166→            <NavLink
   167→              key={path}
   168→              label={label}
   169→              leftSection={
   170→                <Text size="xs" c="dimmed" style={{ width: 16, textAlign: "center", fontFamily: "monospace" }}>
   171→                  {sym}
   172→                </Text>
   173→              }
   174→              active={activeNav === path}
   175→              onClick={() => navigate(path)}
   176→              styles={{ root: { borderRadius: 6, marginBottom: 2, fontSize: 13 } }}
   177→            />
   178→          ))}
   179→        </Box>
   180→
   181→        <Group
   182→          justify="space-between"
   183→          px={8}
   184→          pt={10}
   185→          style={{ borderTop: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))" }}
   186→        >
   187→          <Text size="xs" c="dimmed">v0.1</Text>
   188→          <Tooltip label={colorScheme === "dark" ? "Light mode" : "Dark mode"} position="right" withArrow>
   189→            <ActionIcon variant="subtle" color="gray" onClick={toggleColorScheme} size="sm">
   190→              {colorScheme === "dark" ? "☀" : "◐"}
   191→            </ActionIcon>
   192→          </Tooltip>
   193→        </Group>
   194→      </AppShell.Navbar>
   195→
   196→      <AppShell.Main
   197→        style={{
   198→          display: "flex",
   199→          flexDirection: "column",
   200→          overflow: "hidden",
   201→          height: "100vh",
   202→          padding: 0,
   203→          paddingTop: 40, // offset for the header
   204→        }}
   205→      >
   206→        <Box style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column" }}>
   207→          <Outlet />
   208→        </Box>
   209→      </AppShell.Main>
   210→    </AppShell>
   211→  );
   212→}
