     1→import React, { useCallback, useEffect, useState } from "react";
     2→import { useNavigate } from "react-router-dom";
     3→import {
     4→  Center, Loader, Alert, Text, Box, Badge, Group, UnstyledButton, Code, ScrollArea,
     5→} from "@mantine/core";
     6→import { fetchCheckpoints, subscribeToUpdates, type Checkpoint } from "../api";
     7→import { TimeAgo } from "../components/TimeAgo";
     8→
     9→function CheckpointCard({ checkpoint, onPress }: { checkpoint: Checkpoint; onPress: () => void }) {
    10→  const title = checkpoint.summary?.intent ?? checkpoint.checkpointId;
    11→  const shortId = checkpoint.checkpointId.slice(0, 12);
    12→  const outTokens = checkpoint.tokenUsage?.outputTokens ?? 0;
    13→  const tokStr = outTokens >= 1000
    14→    ? `${(outTokens / 1000).toFixed(1)}k tokens`
    15→    : outTokens > 0 ? `${outTokens} tokens` : null;
    16→  const fileCount = checkpoint.filesTouched.length;
    17→
    18→  return (
    19→    <UnstyledButton
    20→      onClick={onPress}
    21→      style={{ width: "100%", display: "block", padding: "16px 20px", borderBottom: "1px solid var(--mantine-color-dark-4)" }}
    22→      styles={{ root: { "&:hover": { backgroundColor: "var(--mantine-color-dark-5)" } } }}
    23→    >
    24→      <Group justify="space-between" align="flex-start" wrap="nowrap" gap="xl">
    25→        <Box style={{ flex: 1, minWidth: 0 }}>
    26→          <Text fw={600} size="sm" mb={6} style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
    27→            {title}
    28→          </Text>
    29→          <Group gap={6} wrap="wrap" align="center">
    30→            <Code fz={11} style={{ borderRadius: 4, padding: "1px 6px" }}>{shortId}</Code>
    31→            {checkpoint.createdAt && (
    32→              <>
    33→                <Text size="xs" c="dimmed">·</Text>
    34→                <TimeAgo iso={checkpoint.createdAt} />
    35→              </>
    36→            )}
    37→            {checkpoint.branch && (
    38→              <>
    39→                <Text size="xs" c="dimmed">·</Text>
    40→                <Badge variant="outline" color="teal" size="xs" radius="sm">{checkpoint.branch}</Badge>
    41→              </>
    42→            )}
    43→            <Text size="xs" c="dimmed">·</Text>
    44→            <Badge variant="outline" color="orange" size="xs" radius="sm" ff="monospace">Claude Code</Badge>
    45→          </Group>
    46→        </Box>
    47→
    48→        <Group gap={6} style={{ flexShrink: 0, alignSelf: "center" }} wrap="nowrap">
    49→          {fileCount > 0 && (
    50→            <Text size="xs" c="dimmed">{fileCount} file{fileCount !== 1 ? "s" : ""}</Text>
    51→          )}
    52→          {checkpoint.sessionCount > 0 && (
    53→            <>
    54→              <Text size="xs" c="dimmed">·</Text>
    55→              <Text size="xs" c="dimmed">{checkpoint.sessionCount} session{checkpoint.sessionCount !== 1 ? "s" : ""}</Text>
    56→            </>
    57→          )}
    58→          {tokStr && (
    59→            <>
    60→              <Text size="xs" c="dimmed">·</Text>
    61→              <Text size="xs" c="dimmed">{tokStr}</Text>
    62→            </>
    63→          )}
    64→        </Group>
    65→      </Group>
    66→    </UnstyledButton>
    67→  );
    68→}
    69→
    70→export function Checkpoints() {
    71→  const navigate = useNavigate();
    72→  const [checkpoints, setCheckpoints] = useState<Checkpoint[]>([]);
    73→  const [loading, setLoading] = useState(true);
    74→  const [error, setError] = useState<string | null>(null);
    75→
    76→  const load = useCallback(async () => {
    77→    try {
    78→      setCheckpoints(await fetchCheckpoints());
    79→      setError(null);
    80→    } catch (err) {
    81→      setError(String(err));
    82→    }
    83→  }, []);
    84→
    85→  useEffect(() => {
    86→    load().finally(() => setLoading(false));
    87→    return subscribeToUpdates(() => { load().catch(() => undefined); });
    88→  }, [load]);
    89→
    90→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="teal" /></Center>;
    91→  if (error) return <Center style={{ flex: 1, padding: 24 }}><Alert color="red" title="Error" maw={480}>{error}</Alert></Center>;
    92→  if (checkpoints.length === 0) return <Center style={{ flex: 1 }}><Text c="dimmed" size="sm">No checkpoints indexed yet.</Text></Center>;
    93→
    94→  return (
    95→    <ScrollArea style={{ flex: 1 }}>
    96→      <Box>
    97→        {checkpoints.map((cp) => (
    98→          <CheckpointCard
    99→            key={cp.checkpointId}
   100→            checkpoint={cp}
   101→            onPress={() =>
   102→              navigate(`/checkpoints/${cp.checkpointId}`, {
   103→                state: { title: cp.branch ? `${cp.branch} · ${cp.checkpointId}` : cp.checkpointId, localPath: cp.localPath },
   104→              })
   105→            }
   106→          />
   107→        ))}
   108→      </Box>
   109→    </ScrollArea>
   110→  );
   111→}
