     1→import React, { useEffect, useState } from "react";
     2→import { useNavigate, useParams, useLocation } from "react-router-dom";
     3→import { Center, Loader, Text, ScrollArea, Box, Badge, Group, UnstyledButton } from "@mantine/core";
     4→import { fetchCheckpoint, fetchCheckpointDiff, type Checkpoint, type CheckpointSummary, type OpenItem } from "../api";
     5→import { html as diff2htmlHtml } from "diff2html";
     6→import "diff2html/bundles/css/diff2html.min.css";
     7→import "../diff2html-theme.css";
     8→import { InlineMarkdown } from "../components/MarkdownView";
     9→
    10→function SectionBlock({ title, color = "dimmed", children }: { title: string; color?: string; children: React.ReactNode }) {
    11→  return (
    12→    <Box style={{ borderLeft: "2px solid light-dark(var(--mantine-color-teal-3), var(--mantine-color-teal-8))", paddingLeft: 10 }}>
    13→      <Text size="xs" fw={600} c={color} mb={5} tt="uppercase" style={{ letterSpacing: 0.4 }}>{title}</Text>
    14→      {children}
    15→    </Box>
    16→  );
    17→}
    18→
    19→function BulletList({ items, color }: { items: string[]; color?: string }) {
    20→  return (
    21→    <Box style={{ display: "flex", flexDirection: "column", gap: 3 }}>
    22→      {items.map((it, i) => (
    23→        <Group key={i} gap={6} wrap="nowrap" align="flex-start">
    24→          <Text size="xs" c={color ?? "teal"} style={{ flexShrink: 0, lineHeight: 1.6 }}>·</Text>
    25→          <InlineMarkdown text={it} style={{ fontSize: 12, lineHeight: 1.6 }} />
    26→        </Group>
    27→      ))}
    28→    </Box>
    29→  );
    30→}
    31→
    32→function SummaryDetail({ summary, diff, fileCount }: { summary: CheckpointSummary | null; diff: string | null; fileCount: number }) {
    33→  return (
    34→    <Box style={{ display: "flex", flexDirection: "column", gap: 14, padding: "16px 20px" }}>
    35→      {summary?.intent && (
    36→        <Text size="sm" fs="italic" c="dimmed">{summary.intent}</Text>
    37→      )}
    38→
    39→      {summary?.outcome && (
    40→        <SectionBlock title="Outcome">
    41→          <InlineMarkdown text={summary.outcome} style={{ fontSize: 12, lineHeight: 1.6 }} />
    42→        </SectionBlock>
    43→      )}
    44→
    45→      {(summary?.repoLearnings?.length ?? 0) > 0 && (
    46→        <SectionBlock title="Repo learnings">
    47→          <BulletList items={summary!.repoLearnings} />
    48→        </SectionBlock>
    49→      )}
    50→
    51→      {(summary?.codeLearnings?.length ?? 0) > 0 && (
    52→        <SectionBlock title="Code learnings">
    53→          <Box style={{ display: "flex", flexDirection: "column", gap: 8 }}>
    54→            {summary!.codeLearnings.map((it, i) => (
    55→              <Box key={i}>
    56→                <Text size="xs" ff="monospace" c="violet" fw={600} mb={2}>{it.path}</Text>
    57→                <Box pl={8}><InlineMarkdown text={`→ ${it.finding}`} style={{ fontSize: 12, lineHeight: 1.6 }} /></Box>
    58→              </Box>
    59→            ))}
    60→          </Box>
    61→        </SectionBlock>
    62→      )}
    63→
    64→      {(summary?.workflowLearnings?.length ?? 0) > 0 && (
    65→        <SectionBlock title="Workflow learnings">
    66→          <BulletList items={summary!.workflowLearnings} />
    67→        </SectionBlock>
    68→      )}
    69→
    70→      {(summary?.friction?.length ?? 0) > 0 && (
    71→        <SectionBlock title="Friction" color="orange">
    72→          <BulletList items={summary!.friction} color="orange" />
    73→        </SectionBlock>
    74→      )}
    75→
    76→      {(summary?.openItems?.length ?? 0) > 0 && (
    77→        <SectionBlock title="Open items">
    78→          <Box style={{ display: "flex", flexDirection: "column", gap: 5 }}>
    79→            {summary!.openItems.map((it: OpenItem) => {
    80→              const statusColor = it.status === "complete" ? "teal" : it.status === "in_progress" ? "orange" : it.status === "na" ? "gray" : "blue";
    81→              const statusLabel = it.status === "in_progress" ? "in progress" : it.status === "na" ? "n/a" : it.status;
    82→              return (
    83→                <Group key={it.id} gap={8} wrap="nowrap" align="flex-start">
    84→                  <Badge color={statusColor} size="xs" variant="light" style={{ flexShrink: 0, marginTop: 2, textTransform: "none" }}>{statusLabel}</Badge>
    85→                  <InlineMarkdown text={it.text} style={{ fontSize: 12, lineHeight: 1.6 }} />
    86→                </Group>
    87→              );
    88→            })}
    89→          </Box>
    90→        </SectionBlock>
    91→      )}
    92→
    93→      <SectionBlock title="Files changed">
    94→        {diff === null ? (
    95→          <Text size="xs" c="dimmed">Loading…</Text>
    96→        ) : diff === "" ? (
    97→          fileCount > 0 ? (
    98→            <Text size="xs" c="dimmed">{fileCount} file{fileCount !== 1 ? "s" : ""} changed (diff not available)</Text>
    99→          ) : (
   100→            <Text size="xs" c="dimmed">No changes</Text>
   101→          )
   102→        ) : (
   103→          <Box
   104→            className="d2h-wrapper"
   105→            style={{ fontSize: 12, overflowX: "auto" }}
   106→            dangerouslySetInnerHTML={{
   107→              __html: diff2htmlHtml(diff, {
   108→                drawFileList: true,
   109→                matching: "lines",
   110→                outputFormat: "line-by-line",
   111→                colorScheme: "light",
   112→              }),
   113→            }}
   114→          />
   115→        )}
   116→      </SectionBlock>
   117→    </Box>
   118→  );
   119→}
