   121→export function CheckpointDetail() {
   122→  const navigate = useNavigate();
   123→  const { checkpointId } = useParams<{ checkpointId: string }>();
   124→  const location = useLocation();
   125→  const localPath = (location.state as { localPath?: string | null } | null)?.localPath ?? null;
   126→  const [checkpoint, setCheckpoint] = useState<Checkpoint | null>(null);
   127→  const [diff, setDiff] = useState<string | null>(null);
   128→  const [loading, setLoading] = useState(true);
   129→  const [error, setError] = useState<string | null>(null);
   130→
   131→  const id = checkpointId!;
   132→
   133→  useEffect(() => {
   134→    fetchCheckpoint(id, localPath)
   135→      .then((cp) => {
   136→        setCheckpoint(cp);
   137→        setError(null);
   138→        return fetchCheckpointDiff(id, localPath);
   139→      })
   140→      .then((d) => setDiff(d ?? ""))
   141→      .catch((err: unknown) => setError(String(err)))
   142→      .finally(() => setLoading(false));
   143→  }, [id]);
   144→
