    71→function highlightText(text: string, terms: string[]): React.ReactNode {
    72→  if (!terms.length) return text;
    73→  const pattern = terms.map((t) => t.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")).join("|");
    74→  const parts = text.split(new RegExp(`(${pattern})`, "gi"));
    75→  return (
    76→    <>
    77→      {parts.map((p, i) =>
    78→        i % 2 === 1
    79→          ? <mark key={i} style={{ background: "rgba(255,200,0,0.45)", borderRadius: 2, padding: "0 1px" }}>{p}</mark>
    80→          : p
    81→      )}
    82→    </>
    83→  );
    84→}
