   362→export function groupEvents(events: Event[]): DisplayItem[] {
   363→  const postMap = new Map<string, Event>();
   364→  for (const event of events) {
   365→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
   366→      const d = event.data as Record<string, unknown>;
   367→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   368→      if (id) postMap.set(id, event);
   369→    }
   370→  }
   371→
   372→  type RawItem =
   373→    | { kind: "event"; event: Event }
   374→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
   375→
   376→  const raw: RawItem[] = [];
   377→  const consumed = new Set<number>();
   378→
   379→  for (const event of events) {
   380→    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
   381→    if (event.event === "PreToolUse") {
   382→      const d = event.data as Record<string, unknown>;
   383→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   384→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
   385→      if (post) consumed.add(post.id);
   386→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
   387→      continue;
   388→    }
   389→    raw.push({ kind: "event", event });
   390→  }
   391→
   392→  const isGroupable = (item: RawItem) =>
   393→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
   394→
   395→  const result: DisplayItem[] = [];
   396→  let i = 0;
   397→  while (i < raw.length) {
   398→    if (isGroupable(raw[i])) {
   399→      const group: ToolUseData[] = [];
   400→      while (i < raw.length && isGroupable(raw[i])) {
   401→        const item = raw[i];
   402→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
   403→        i++;
   404→      }
   405→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
   406→    } else {
   407→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
   408→      i++;
   409→    }
   410→  }
   411→  return result;
   412→}
