   571→
   572→function extractMatchTerms(snippet: string): string[] {
   573→  const terms: string[] = [];
   574→  const re = /«([^»]+)»/g;
   575→  let m: RegExpExecArray | null;
   576→  while ((m = re.exec(snippet)) !== null) terms.push(m[1]);
   577→  return [...new Set(terms)];
   578→}
   579→
   580→// ── Source log event ID extractor ─────────────────────────────────────────────
   581→
   582→function getItemSourceIds(item: RenderItem): number[] {
   583→  if (item.kind === "event") {
   584→    const ids = item.event._sourceLogEventId != null ? [item.event._sourceLogEventId] : [];
   585→    if (item.event._extraSourceLogEventIds) ids.push(...item.event._extraSourceLogEventIds);
   586→    return ids;
   587→  }
   588→  if (item.kind === "claudeTurn") {
   589→    const ids: number[] = [];
   590→    for (const group of item.toolGroups) {
   591→      for (const tool of group) {
   592→        if (tool.pre._sourceLogEventId != null) ids.push(tool.pre._sourceLogEventId);
   593→        if (tool.pre._extraSourceLogEventIds) ids.push(...tool.pre._extraSourceLogEventIds);
   594→        if (tool.post?._sourceLogEventId != null) ids.push(tool.post._sourceLogEventId);
   595→        if (tool.post?._extraSourceLogEventIds) ids.push(...tool.post._extraSourceLogEventIds);
   596→      }
   597→    }
   598→    if (item.stop?._sourceLogEventId != null) ids.push(item.stop._sourceLogEventId);
   599→    if (item.stop?._extraSourceLogEventIds) ids.push(...item.stop._extraSourceLogEventIds);

