     1→import React, { useEffect, useState } from "react";
     2→import { Box, Badge, Group, Text, Collapse } from "@mantine/core";
     3→import type { Event } from "../api";
     4→import { ToolUseItem } from "./ToolUseItem";
     5→import { relativeTime } from "./TimeAgo";
     6→
     7→export interface ToolUseData {
     8→  pre: Event;
     9→  post?: Event;
    10→  failed: boolean;
    11→}
    12→
    13→function toolName(pre: Event): string {
    14→  const d = pre.data as Record<string, unknown>;
    15→  return typeof d.tool_name === "string" ? d.tool_name : "?";
    16→}
    17→
    18→export function ToolGroupItem({ tools, autoExpand, matchTerms, targetLogEventId }: {
    19→  tools: ToolUseData[];
    20→  autoExpand?: boolean;
    21→  matchTerms?: string[];
    22→  targetLogEventId?: number | null;
    23→}) {
    24→  const [expanded, setExpanded] = useState(false);
    25→
    26→  useEffect(() => {
    27→    if (autoExpand) setExpanded(true);
    28→  }, [autoExpand]);
    29→
    30→  const names = tools.map((t) => toolName(t.pre));
    31→  const counts = new Map<string, number>();
    32→  for (const n of names) counts.set(n, (counts.get(n) ?? 0) + 1);
    33→  const summary = [...counts.entries()].map(([n, c]) => (c > 1 ? `${n} ×${c}` : n)).join(", ");
    34→
    35→  const anyFailed  = tools.some((t) => t.failed);
    36→  const anyPending = tools.some((t) => !t.post);
    37→  const anyBlocked = tools.some((t) => t.pre.blocked);
    38→
    39→  const statusColor = anyFailed ? "red" : anyPending ? "blue" : "teal";
    40→  const statusLabel = anyFailed ? "failed" : anyPending ? "running" : "done";
    41→
    42→  const timeStart = relativeTime(tools[0].pre.timestamp);
    43→  const lastPost  = [...tools].reverse().find((t) => t.post)?.post;
    44→  const timeEnd   = lastPost ? relativeTime(lastPost.timestamp) : undefined;
    45→  const showRange = timeEnd && timeEnd !== timeStart;
    46→
    47→  return (
    48→    <Box style={{
    49→      border: "1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-4))",
    50→      borderRadius: 8,
    51→      overflow: "hidden",
    52→      backgroundColor: "light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-7))",
    53→    }}>
    54→        <Group
    55→          gap={8}
    56→          px={12}
    57→          py={7}
    58→          onClick={() => setExpanded((v) => !v)}
    59→          style={{ cursor: "pointer" }}
    60→        >
    61→          <Badge size="xs" variant="light" color={statusColor}>{statusLabel}</Badge>
    62→          <Text size="xs" c="dimmed" style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
    63→            {tools.length} tool {tools.length === 1 ? "use" : "uses"} — {summary}
    64→          </Text>
    65→          {anyBlocked && <Badge color="red" size="xs" variant="filled" fw={700}>BLOCKED</Badge>}
    66→          <Text size="xs" c="dimmed">{timeStart}{showRange ? ` → ${timeEnd}` : ""}</Text>
    67→          <Text size="xs" c="dimmed">{expanded ? "▲" : "▼"}</Text>
    68→        </Group>
    69→        <Collapse in={expanded}>
    70→          <Box style={{ borderTop: "1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-4))" }}>
    71→            {tools.map((t, i) => {
    72→              const isMatch = targetLogEventId != null && (
    73→                t.pre._sourceLogEventId === targetLogEventId ||
    74→                t.post?._sourceLogEventId === targetLogEventId
    75→              );
    76→              return <ToolUseItem key={i} pre={t.pre} post={t.post} failed={t.failed} autoExpand={isMatch} matchTerms={isMatch ? matchTerms : undefined} />;
    77→            })}
    78→          </Box>
    79→        </Collapse>
    80→    </Box>
    81→  );
    82→}
    83→

