    62→
    63→  const [items, setItems]               = useState<BranchLogEntry[]>([]);
    64→  const [page, setPage]                 = useState(0);
    65→  const [hasMore, setHasMore]           = useState(false);
    66→  const [loading, setLoading]           = useState(true);
    67→  const [loadingMore, setLoadingMore]   = useState(false);
    68→  const [error, setError]               = useState<string | null>(null);
    69→
    70→  const [liveSession, setLiveSession]   = useState<BranchLiveSession | null>(null);
    71→  const [selectedId, setSelectedId]     = useState<string | null>(null);
    72→  const [rightItems, setRightItems]     = useState<RenderItem[]>([]);
    73→  const [rightLoading, setRightLoading] = useState(false);
    74→
    75→  // Cache raw log events per sessionId to avoid redundant fetches
    76→  const sessionEventsCache = useRef<Map<string, LogEventItem[]>>(new Map());
    77→
    78→  const { setCrumbs } = useBreadcrumb();
    79→
    80→  function applyEntry(entry: BranchLogEntry, allItems: BranchLogEntry[], cachedEvents: LogEventItem[]) {
    81→    const sessionEntries = allItems.filter((e) => e.sessionId === entry.sessionId);
    82→    const filtered = filterEventsForEntry(entry, sessionEntries, cachedEvents);
    83→    setRightItems(groupClaudeTurns(groupEvents(logEventsToEvents(filtered))));
    84→  }
    85→
    86→  function loadLivePanel(sessionId: string) {
    87→    const cached = sessionEventsCache.current.get(sessionId);
