   380→
   381→export function subscribeToUpdates(onUpdate: () => void): () => void {
   382→  let ws: WebSocket | null = null;
   383→  let timer: ReturnType<typeof setTimeout> | null = null;
   384→  let closed = false;
   385→  let delay = 1000;
   386→
   387→  function connect() {
   388→    if (closed) return;
   389→    ws = new WebSocket(WS_URL);
   390→
   391→    ws.onopen = () => {
   392→      delay = 1000; // reset backoff on successful connection
   393→    };
   394→
   395→    ws.onmessage = (e) => {
   396→      try {
   397→        const msg = JSON.parse(e.data as string) as { type: string };
   398→        if (msg.type === "sessions_updated") onUpdate();
   399→      } catch {
   400→        // ignore malformed messages
   401→      }
   402→    };
   403→
   404→    ws.onclose = () => {
   405→      if (closed) return;
   406→      timer = setTimeout(() => {
   407→        delay = Math.min(delay * 2, 30000);
   408→        connect();
   409→      }, delay);
   410→    };
   411→
   412→    ws.onerror = () => {
   413→      ws?.close();
   414→    };
   415→  }
   416→
   417→  connect();
   418→
