   121→export function CheckpointDetail() {
   122→  const navigate = useNavigate();
   123→  const { checkpointId } = useParams<{ checkpointId: string }>();
   124→  const location = useLocation();
   125→  const localPath = (location.state as { localPath?: string | null } | null)?.localPath ?? null;
   126→  const [checkpoint, setCheckpoint] = useState<Checkpoint | null>(null);
   127→  const [diff, setDiff] = useState<string | null>(null);
   128→  const [loading, setLoading] = useState(true);
   129→  const [error, setError] = useState<string | null>(null);
   130→
   131→  const id = checkpointId!;
   132→
   133→  useEffect(() => {
   134→    fetchCheckpoint(id, localPath)
   135→      .then((cp) => {
   136→        setCheckpoint(cp);
   137→        setError(null);
   138→        return fetchCheckpointDiff(id, localPath);
   139→      })
   140→      .then((d) => setDiff(d ?? ""))
   141→      .catch((err: unknown) => setError(String(err)))
   142→      .finally(() => setLoading(false));
   143→  }, [id]);
   144→
   145→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="teal" /></Center>;
   146→  if (error)   return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
   147→  if (!checkpoint) return null;
   148→
   149→  const outTokens = checkpoint.tokenUsage?.outputTokens ?? 0;
   150→  const fileCount = checkpoint.filesTouched.length;
   151→
   152→  return (
   153→    <ScrollArea style={{ flex: 1 }}>
   154→      <Box style={{ maxWidth: 860, margin: "0 auto", paddingBottom: 40 }}>
   155→
   156→        {/* Header */}
   157→        <Box
   158→          style={{
   159→            display: "flex", alignItems: "center", gap: 10,
   160→            padding: "8px 20px",
   161→            backgroundColor: "light-dark(var(--mantine-color-teal-0), var(--mantine-color-dark-6))",
   162→            borderBottom: "1px solid light-dark(var(--mantine-color-teal-2), var(--mantine-color-dark-4))",
   163→          }}
   164→        >
   165→          <Box style={{ flex: 1 }}>
   166→            <Group gap={8} mb={2}>
   167→              <Text size="xs" fw={700} c="teal" tt="uppercase">Checkpoint</Text>
   168→              <Text ff="monospace" size="xs" c="green" fw={600}>{checkpoint.checkpointId}</Text>
   169→              {checkpoint.branch && (
   170→                <UnstyledButton onClick={() => navigate("/checkpoints/timeline")}>
   171→                  <Badge variant="light" color="teal" size="xs" style={{ cursor: "pointer" }}>{checkpoint.branch}</Badge>
   172→                </UnstyledButton>
   173→              )}
   174→            </Group>
   175→            {checkpoint.summary?.intent && (
   176→              <Text size="xs" c="dimmed" fs="italic">{checkpoint.summary.intent}</Text>
   177→            )}
   178→          </Box>
   179→          <Box style={{ textAlign: "right", flexShrink: 0 }}>
   180→            {fileCount > 0 && <Text size="xs" c="dimmed" ff="monospace">{fileCount} file{fileCount !== 1 ? "s" : ""}</Text>}
   181→            {outTokens > 0 && <Text size="xs" c="dimmed" ff="monospace">{outTokens.toLocaleString()} tok</Text>}
   182→          </Box>
   183→        </Box>
   184→
   185→        <SummaryDetail summary={checkpoint.summary} diff={diff} fileCount={fileCount} />
   186→
   187→      </Box>
   188→    </ScrollArea>
   189→  );
   190→}
