      </Center>
    );
  }

  const selectedEntry = items.find((e) => entryKey(e) === selectedId) ?? null;
  const userInfo: UserInfo | undefined = selectedEntry
    ? (() => {
        const name = selectedEntry.gitUserName ?? selectedEntry.gitUserEmail ?? null;
